mapper.insert:
insert into pm_project_property_af_from_sms ( id, `orderExecNumber`, `projectCode`, `projectName`, `salesManCode`, `salesManName`, `marketCode`, `marketName`, `systemId`, `systemName`, `expendId`, `expendName`, `industryId`, `industryName`, `officeCode`, `officeName`, `serviceTypeName`, `channelName`, `engineeFee`, `objId`, `applyType`, `corporationCode`, `customerProjectName`, `finalCustomerName`, `agentName`, projectType, projectMoney, afProjectMoney, submitTime, predBidDate ) select distinct ppfs.id, ppfs.`orderExecNumber`, ppfs.`projectCode`, `projectName`, `salesManCode`, `salesManName`, `marketCode`, `marketName`, `systemId`, `systemName`, `expendId`, `expendName`, `industryId`, `industryName`, `officeCode`, `officeName`, `serviceTypeName`, `channelName`, `engineeFee`, ifnull(`objId`, 0) as objId, `applyType`, ppfs.`corporationCode`, `customerProjectName`, `finalCustomerName`, `agentName`, "afss" as projectType, projectMoney, ROUND(SUM(ppfd.purchasePrice * ppfd.num), 2) as afProjectMoney, submitTime, predBidDate from `pm_project_property_from_sms` ppfs inner join `pm_project_product_af_from_sms` ppfd on ppfs.`orderExecNumber` = ppfd.`orderExecNumber` and ppfs.`projectCode` = ppfd.`projectCode`
FIND_IN_SET(ppfd.`productfirstCode`, #{_parameter})
group by ppfs.`id` ;
